    # ========== PUBLIC ==========
    def get_price(self, symbol):
        data = self._get('/fapi/v1/ticker/price', {'symbol': symbol})
        if 'error' not in data:
            return float(data['price'])
        return None

    def get_candles(self, symbol, interval='15m', limit=100):
        data = self._get('/fapi/v1/klines', {
            'symbol': symbol, 'interval': interval, 'limit': limit
        })
        if isinstance(data, list):
            candles = []
            for c in data:
                candles.append({
                    'time': c[0],
                    'open': float(c[1]),
                    'high': float(c[2]),
                    'low': float(c[3]),
                    'close': float(c[4]),
                    'volume': float(c[5]),
                    'quote_vol': float(c[7]),
                    'trades': int(c[8]),
                    'taker_buy_vol': float(c[9]),
                    'taker_buy_quote': float(c[10]),
                })
            return candles
        return []

    def get_agg_trades(self, symbol, limit=500):
        data = self._get('/fapi/v1/aggTrades', {
            'symbol': symbol, 'limit': limit
        })
        if isinstance(data, list):
            trades = []
            for t in data:
                trades.append({
                    'price': float(t['p']),
                    'qty': float(t['q']),
                    'time': t['T'],
                    'is_buyer_maker': t['m'],  # True = seller initiated
                })
            return trades
        return []

    def get_depth(self, symbol, limit=20):
        data = self._get('/fapi/v1/depth', {
            'symbol': symbol, 'limit': limit
        })
        if 'bids' in data:
            return {
                'bids': [[float(p), float(q)] for p, q in data['bids']],
                'asks': [[float(p), float(q)] for p, q in data['asks']],
                'time': data.get('lastUpdateId', 0),
            }
        return None

    def get_exchange_info(self, symbol=None):
        data = self._get('/fapi/v1/exchangeInfo')
        if 'symbols' in data:
            if symbol:
                for s in data['symbols']:
                    if s['symbol'] == symbol:
                        return s
            return data['symbols']
        return data

    # ========== SIGNED ==========
    def get_account(self):
        return self._get('/fapi/v2/account', signed=True)

    def get_balance(self):
        data = self._get('/fapi/v2/balance', signed=True)
        if isinstance(data, list):
            for b in data:
                if b['asset'] == 'USDT':
                    return {
                        'balance': float(b['balance']),
                        'available': float(b['availableBalance']),
                        'unrealized': float(b.get('crossUnPnl', 0)),
                    }
        return None

    def get_positions(self):
        data = self._get('/fapi/v2/positionRisk', signed=True)
        if isinstance(data, list):
            return [p for p in data if float(p.get('positionAmt', 0)) != 0]
        return []

    def get_open_orders(self, symbol=None):
        params = {}
        if symbol:
            params['symbol'] = symbol
        data = self._get('/fapi/v1/openOrders', params, signed=True)
        if isinstance(data, list):
            return data
        return []

    def set_leverage(self, symbol, leverage):
        return self._post('/fapi/v1/leverage', {
            'symbol': symbol, 'leverage': leverage
        })

    def set_position_mode(self, dual=True):
        mode = 'true' if dual else 'false'
        return self._post('/fapi/v1/positionSide/dual', {'dualSidePosition': mode})

    def market_order(self, symbol, side, quantity, reduce_only=False):
        params = {
            'symbol': symbol,
            'side': side.upper(),
            'type': 'MARKET',
            'quantity': quantity,
        }
        if reduce_only:
            params['reduceOnly'] = 'true'
        return self._post('/fapi/v1/order', params)

    def limit_order(self, symbol, side, quantity, price, time_in_force='GTC'):
        return self._post('/fapi/v1/order', {
            'symbol': symbol,
            'side': side.upper(),
            'type': 'LIMIT',
            'quantity': quantity,
            'price': price,
            'timeInForce': time_in_force,
        })

    def stop_market(self, symbol, side, quantity, stop_price):
        """Place STOP_MARKET via Algo Order API (required by testnet since Dec 2025)."""
        return self._algo_order(symbol, 'STOP_MARKET', side, quantity, stop_price)

    def take_profit_market(self, symbol, side, quantity, stop_price):
        """Place TAKE_PROFIT_MARKET via Algo Order API (required by testnet since Dec 2025)."""
        return self._algo_order(symbol, 'TAKE_PROFIT_MARKET', side, quantity, stop_price)

    def _algo_order(self, symbol, order_type, side, quantity, trigger_price):
        """
        Place algo order (CONDITIONAL) via POST /fapi/v1/algoOrder.
        Verified working on testnet. Uses 'triggerPrice' (camelCase).
        IMPORTANT: reduceOnly='true' supaya cuma CLOSE posisi, bukan OPEN baru.
        """
        return self._post('/fapi/v1/algoOrder', {
            'symbol': symbol,
            'side': side.upper(),
            'type': order_type,
            'algoType': 'CONDITIONAL',
            'triggerPrice': str(trigger_price),
            'quantity': str(quantity),
            'workingType': 'MARK_PRICE',
            'reduceOnly': 'true',
        })

    def cancel_algo_order(self, symbol, algo_id):
        """Cancel algo order via DELETE /fapi/v1/algoOrder (verified working)."""
        return self._delete('/fapi/v1/algoOrder', {
            'symbol': symbol,
            'algoId': algo_id,
        })

    def cancel_all_algo_orders(self, symbol, algo_ids=None):
        """Cancel algo orders. Pass algo_ids list or cancel by symbol.
        NOTE: Testnet has no list endpoint, so we need tracked IDs."""
        results = []
        if algo_ids:
            for aid in algo_ids:
                r = self.cancel_algo_order(symbol, aid)
                results.append(r)
        return results

    def cancel_order(self, symbol, order_id):
        return self._delete('/fapi/v1/order', {
            'symbol': symbol, 'orderId': order_id
        })

    def cancel_all_orders(self, symbol, algo_ids=None):
